card.js:
let liveHass = hass;

const card = root.querySelector('[data-neo-light]');
const stage = root.querySelector('[data-nlc-stage]');
const toggleTarget = root.querySelector('[data-nlc-toggle]');
const iconEl = root.querySelector('[data-nlc-icon]');
const labelEl = root.querySelector('[data-nlc-label]');
const statusEl = root.querySelector('[data-nlc-status]');
const percentEl = root.querySelector('[data-nlc-percent]');
const cardNameEl = root.querySelector('[data-nlc-card-name]');
const configOpen = root.querySelector('[data-nlc-config-open]');
const configPanel = root.querySelector('[data-nlc-config]');
const configClose = root.querySelector('[data-nlc-config-close]');
const configSave = root.querySelector('[data-nlc-config-save]');

const DESIGN_W = 360;
const DESIGN_H = 500;
const NEO_CONFIG_FIELD = 'neo_light_config';
const STYLE_OPTIONS = new Set([
  'toggle-switch',
  'slider-switch',
  'circle-button',
  'icon-switch',
  'rocker-switch',
  'card-switch',
  'dot-switch',
  'ring-dimmer',
  'wave-toggle',
  'minimal-dot'
]);
const PERSISTED_CONFIG_KEYS = [
  'entity',
  'icon',
  'label',
  'style',
  'showBrightness',
  'defaultBrightness',
  'colorOn',
  'colorAlt',
  'colorOff'
];

let resizeFrame = null;
let lastSignature = '';
let lastStateSignature = '';
let lastScaleSignature = '';
let lastSurfaceSignature = '';
let surfaceMutationObserver = null;
let destroyed = false;
let optimisticState = null;
let pulseTimer = null;
let activeDimmer = null;

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function numberOrFallback(value, fallback) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function boolAttr(value) {
  return ['true', '1', 'yes', 'on'].includes(String(value || '').toLowerCase());
}

function cloneJson(value, fallback) {
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {
    return fallback;
  }
}

function getCardWrapper() {
  return host && host.closest ? host.closest('.card-wrapper') : null;
}

function getConfigStorageKey() {
  const wrap = getCardWrapper();
  const cardId =
    (wrap && wrap.dataset && wrap.dataset.layoutCardId) ||
    (host && host.dataset && host.dataset.layoutCardId) ||
    (host && host.id) ||
    'default-card';

  let dashboardId = 'dashboard';
  try {
    dashboardId = String(
      (ddc && ddc.storageKey) ||
      (ddc && ddc.storage_key) ||
      (ddc && ddc.settings && ddc.settings.get && ddc.settings.get('storage_key')) ||
      (location && location.pathname) ||
      'dashboard'
    );
  } catch {}

  return 'neo-light-card-config:v1:' + dashboardId + ':' + cardId;
}

function isTransparentCssValue(value) {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return false;
  if (v === 'transparent') return true;
  if (/rgba?\([^)]*,\s*0(?:\.0+)?\s*\)$/.test(v)) return true;
  if (/rgb\([^)]*\/\s*0(?:\.0+)?%?\s*\)$/.test(v)) return true;
  return false;
}

function readCssVariable(name) {
  const nodes = [card, stage, host, getCardWrapper()].filter(Boolean);
  for (const node of nodes) {
    try {
      const value = getComputedStyle(node).getPropertyValue(name).trim();
      if (value) return value;
    } catch {}
  }
  return '';
}

function parseStyleObject(value) {
  if (!value || typeof value !== 'string') return null;
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch {
    return null;
  }
}

function firstSurfaceValue() {
  for (let i = 0; i < arguments.length; i += 1) {
    const value = String(arguments[i] || '').trim();
    if (value && !isTransparentCssValue(value)) return value;
  }
  return '';
}

function wrapperCardStyle() {
  const wrap = getCardWrapper();
  if (!wrap || !wrap.dataset) return null;
  return (
    parseStyleObject(wrap.dataset.cardStyle) ||
    parseStyleObject(wrap.dataset.card_style) ||
    parseStyleObject(wrap.dataset.style)
  );
}

function readDesignSurface() {
  const wrap = getCardWrapper();
  const style = wrapperCardStyle();
  const computed = wrap ? getComputedStyle(wrap) : null;
  return firstSurfaceValue(
    style && style.background,
    style && style.card_background,
    style && style.container_background,
    readCssVariable('--ddc-card-inner-bg'),
    readCssVariable('--ddc-card-local-bg'),
    readCssVariable('--ddc-card-bg'),
    computed && computed.backgroundImage !== 'none' ? computed.backgroundImage : '',
    computed && computed.backgroundColor
  );
}

function keepWrapperTransparent() {
  const wrap = getCardWrapper();
  [wrap, host].filter(Boolean).forEach((node) => {
    try {
      node.style.setProperty('--ddc-card-local-bg', 'transparent');
      node.style.setProperty('--ddc-card-inner-bg', 'transparent');
      node.style.setProperty('--ha-card-background', 'transparent');
      node.style.setProperty('--card-background-color', 'transparent');
      node.style.background = 'transparent';
      node.style.boxShadow = 'none';
    } catch {}
  });
}

function syncDesignSurface() {
  if (!card || destroyed) return;

  const surface = readDesignSurface();
  const transparent = !surface || isTransparentCssValue(surface);
  const signature = transparent ? 'transparent' : surface;

  if (signature !== lastSurfaceSignature) {
    lastSurfaceSignature = signature;
    if (transparent) {
      card.dataset.surface = 'transparent';
      card.style.removeProperty('--nlc-design-surface');
    } else {
      delete card.dataset.surface;
      card.style.setProperty('--nlc-design-surface', surface);
    }
  }

  keepWrapperTransparent();
}

function readSourceCardConfig() {
  const wrap = getCardWrapper();

  try {
    const parsed = JSON.parse((wrap && wrap.dataset && wrap.dataset.cfg) || 'null');
    if (parsed && typeof parsed === 'object') return parsed;
  } catch {}

  if (host && host.__ddcSourceConfig && typeof host.__ddcSourceConfig === 'object') {
    return cloneJson(host.__ddcSourceConfig, host.__ddcSourceConfig);
  }

  if (host && host._config && typeof host._config === 'object') {
    return cloneJson(host._config, host._config);
  }

  if (config && typeof config === 'object') {
    return cloneJson(config, config);
  }

  return { type: 'custom:ddc-html-card' };
}

function normalizeSwitchStyle(value) {
  const next = String(value || '').trim().toLowerCase();
  return STYLE_OPTIONS.has(next) ? next : 'toggle-switch';
}

function normalizeConfigValues(values) {
  if (!values || typeof values !== 'object') return null;
  const out = {};

  PERSISTED_CONFIG_KEYS.forEach((key) => {
    if (values[key] === undefined || values[key] === null) return;
    out[key] = String(values[key]);
  });

  if (out.style) out.style = normalizeSwitchStyle(out.style);
  return Object.keys(out).length ? out : null;
}

function applyConfigObject(values) {
  const normalized = normalizeConfigValues(values);
  if (!normalized) return;

  PERSISTED_CONFIG_KEYS.forEach((key) => {
    if (normalized[key] === undefined || normalized[key] === null) return;
    card.dataset[key] = normalized[key];
  });
}

function readLocalConfig() {
  try {
    const raw = localStorage.getItem(getConfigStorageKey());
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return normalizeConfigValues(parsed && parsed.values && typeof parsed.values === 'object' ? parsed.values : parsed);
  } catch {
    return null;
  }
}

function readDurableConfig() {
  const direct = normalizeConfigValues(config && config[NEO_CONFIG_FIELD]);
  if (direct) return direct;

  const source = readSourceCardConfig();
  return normalizeConfigValues(source && source[NEO_CONFIG_FIELD]);
}

function readPersistedConfig() {
  return readDurableConfig() || readLocalConfig();
}

function applyPersistedConfig() {
  applyConfigObject(readPersistedConfig());
}

function collectCurrentConfig() {
  return {
    entity: getEntityId(),
    icon: getIcon(),
    label: getLabel(),
    style: getSwitchStyle(),
    showBrightness: getShowBrightness() ? 'true' : 'false',
    defaultBrightness: String(getDefaultBrightness()),
    colorOn: card.dataset.colorOn || '#ffd95a',
    colorAlt: card.dataset.colorAlt || '#4aa7ff',
    colorOff: card.dataset.colorOff || '#6f7f96'
  };
}

function updateHtmlSourceWithConfig(html, values) {
  if (typeof html !== 'string' || !html.trim()) return html;

  try {
    const template = document.createElement('template');
    template.innerHTML = html;
    const sourceCard = template.content.querySelector('[data-neo-light]');
    if (!sourceCard) return html;

    PERSISTED_CONFIG_KEYS.forEach((key) => {
      if (values[key] === undefined || values[key] === null) return;
      sourceCard.dataset[key] = String(values[key]);
    });

    return template.innerHTML.trim();
  } catch {
    return html;
  }
}

function writeConfigToDdcSource(values) {
  const normalized = normalizeConfigValues(values);
  if (!normalized) return null;

  const wrap = getCardWrapper();
  const source = readSourceCardConfig();
  const next = {
    ...source,
    type: source && source.type ? source.type : 'custom:ddc-html-card',
    [NEO_CONFIG_FIELD]: normalized
  };

  next.html = updateHtmlSourceWithConfig(next.html, normalized);

  try { config[NEO_CONFIG_FIELD] = normalized; } catch {}
  try { host.__ddcSourceConfig = cloneJson(next, next); } catch {}
  try {
    if (host && host._config && typeof host._config === 'object') {
      host._config = { ...host._config, [NEO_CONFIG_FIELD]: normalized, html: next.html };
    }
  } catch {}
  try {
    if (wrap && wrap.dataset) wrap.dataset.cfg = JSON.stringify(next);
  } catch {}

  try {
    const cardId = wrap && wrap.dataset && wrap.dataset.layoutCardId;
    const owner = ddc && ddc.card;
    if (owner && cardId && typeof owner._updateCardConfigAcrossResponsiveLayouts_ === 'function') {
      owner._updateCardConfigAcrossResponsiveLayouts_(cardId, next);
    }
  } catch {}

  return next;
}

async function persistCurrentConfig() {
  const values = collectCurrentConfig();

  try {
    localStorage.setItem(getConfigStorageKey(), JSON.stringify({
      version: 1,
      updatedAt: new Date().toISOString(),
      values
    }));
  } catch {}

  const savedConfig = writeConfigToDdcSource(values);
  if (!savedConfig) return false;

  try { ddc && ddc.card && ddc.card._syncLiveCardConfigsIntoResponsiveLayouts_ && ddc.card._syncLiveCardConfigsIntoResponsiveLayouts_(); } catch {}

  let saved = false;
  try {
    if (ddc && ddc.saveLayout) {
      await ddc.saveLayout(true);
      saved = true;
    }
  } catch {}

  try {
    if (ddc && ddc.card && ddc.card._persistThisCardConfigToStorage_) {
      await ddc.card._persistThisCardConfigToStorage_();
      saved = true;
    }
  } catch {}

  return saved;
}

function getEntityId() {
  return card.dataset.entity || card.getAttribute('entity') || 'light.living_room';
}

function getIcon() {
  return card.dataset.icon || card.getAttribute('icon') || 'mdi:lightbulb-outline';
}

function getLabel() {
  return card.dataset.label || card.getAttribute('label') || 'Light';
}

function getSwitchStyle() {
  return normalizeSwitchStyle(card.dataset.style || card.getAttribute('style-mode') || 'toggle-switch');
}

function getShowBrightness() {
  return boolAttr(card.dataset.showBrightness || card.getAttribute('show-brightness'));
}

function getDefaultBrightness() {
  return clamp(Math.round(numberOrFallback(card.dataset.defaultBrightness || card.getAttribute('default-brightness'), 75)), 1, 100);
}

function getDomain() {
  return String(getEntityId()).split('.')[0] || 'light';
}

function canDim() {
  return getDomain() === 'light';
}

function getStateObj() {
  return liveHass && liveHass.states ? liveHass.states[getEntityId()] : null;
}

function getLightData() {
  const stateObj = getStateObj();
  const now = Date.now();

  if (optimisticState && optimisticState.until > now) {
    return {
      on: optimisticState.on,
      percent: optimisticState.percent,
      state: optimisticState.on ? 'on' : 'off',
      unavailable: false
    };
  }

  optimisticState = null;
  const rawState = String((stateObj && stateObj.state) || 'unavailable').toLowerCase();
  const unavailable = !stateObj || ['unavailable', 'unknown', 'none'].includes(rawState);
  const on = rawState === 'on';
  const rawBrightness = Number(stateObj && stateObj.attributes && stateObj.attributes.brightness);
  const percent = on
    ? clamp(Math.round(Number.isFinite(rawBrightness) ? (rawBrightness / 255) * 100 : getDefaultBrightness()), 1, 100)
    : 0;

  return {
    on,
    percent,
    state: unavailable ? 'unavailable' : rawState,
    unavailable
  };
}

function applyPulse() {
  if (pulseTimer) clearTimeout(pulseTimer);
  card.dataset.stateChange = 'pulse';
  pulseTimer = setTimeout(() => {
    pulseTimer = null;
    if (!destroyed) delete card.dataset.stateChange;
  }, 700);
}

function setOptimistic(on, percent) {
  optimisticState = {
    on: Boolean(on),
    percent: clamp(Math.round(percent), 0, 100),
    until: Date.now() + 1400
  };
  applyPulse();
  lastSignature = '';
  render(true);
}

async function callEntityService(on, percent) {
  if (!liveHass || !liveHass.callService) return;

  const entityId = getEntityId();
  const domain = getDomain() === 'switch' ? 'switch' : 'light';
  const service = on ? 'turn_on' : 'turn_off';
  const data = { entity_id: entityId };

  if (domain === 'light' && on && Number.isFinite(percent)) {
    data.brightness_pct = clamp(Math.round(percent), 1, 100);
  }

  await liveHass.callService(domain, service, data);
}

async function setLightState(nextOn, percent) {
  const safePercent = nextOn ? clamp(Math.round(percent || getDefaultBrightness()), 1, 100) : 0;
  setOptimistic(nextOn, safePercent);

  try {
    await callEntityService(nextOn, safePercent);
  } catch {
    optimisticState = null;
    lastSignature = '';
    render(true);
  }
}

function toggleLight() {
  const data = getLightData();
  return setLightState(!data.on, data.on ? 0 : (data.percent || getDefaultBrightness()));
}

function setBrightness(percent) {
  if (!canDim()) return toggleLight();
  return setLightState(percent > 0, percent);
}

function getViewportElement() {
  return (root && root.parentElement) ||
    (host && host.shadowRoot && host.shadowRoot.querySelector && host.shadowRoot.querySelector('.runtime')) ||
    host ||
    (card && card.parentElement) ||
    card;
}

function getViewportSize() {
  const viewport = getViewportElement();
  const width =
    (viewport && viewport.clientWidth) ||
    (root && root.clientWidth) ||
    (card && card.parentElement && card.parentElement.clientWidth) ||
    DESIGN_W;
  const height =
    (viewport && viewport.clientHeight) ||
    (root && root.clientHeight) ||
    (card && card.parentElement && card.parentElement.clientHeight) ||
    DESIGN_H;

  return {
    width: Math.max(50, width),
    height: Math.max(50, height)
  };
}

function updateScale() {
  if (!card || !stage || destroyed) return;

  const size = getViewportSize();
  const scale = Math.min(size.width / DESIGN_W, size.height / DESIGN_H);
  const scaledW = DESIGN_W * scale;
  const scaledH = DESIGN_H * scale;
  const signature = [
    Math.round(size.width),
    Math.round(size.height),
    scale.toFixed(5)
  ].join('|');

  if (signature === lastScaleSignature) return;
  lastScaleSignature = signature;

  card.style.width = '100%';
  card.style.height = size.height + 'px';
  card.style.minHeight = '0';
  card.style.overflow = 'hidden';

  stage.style.width = DESIGN_W + 'px';
  stage.style.height = DESIGN_H + 'px';
  stage.style.left = Math.max(0, (size.width - scaledW) / 2) + 'px';
  stage.style.top = Math.max(0, (size.height - scaledH) / 2) + 'px';
  stage.style.transform = 'scale(' + scale + ')';
}

function scheduleScale() {
  if (destroyed) return;
  if (resizeFrame) cancelAnimationFrame(resizeFrame);
  resizeFrame = requestAnimationFrame(() => {
    resizeFrame = null;
    updateScale();
  });
}

const resizeObserver = new ResizeObserver(() => {
  syncDesignSurface();
  scheduleScale();
});

Array.from(new Set([getViewportElement(), root, card].filter(Boolean))).forEach((el) => {
  try { resizeObserver.observe(el); } catch {}
});

try {
  const wrap = getCardWrapper();
  if (wrap && typeof MutationObserver !== 'undefined') {
    surfaceMutationObserver = new MutationObserver(() => syncDesignSurface());
    surfaceMutationObserver.observe(wrap, {
      attributes: true,
      attributeFilter: ['style', 'data-card-style', 'data-card_style', 'class']
    });
  }
} catch {}

function setConfigInput(name, value) {
  const input = root.querySelector('[data-cfg="' + name + '"]');
  if (!input) return;

  if (input.type === 'checkbox') {
    input.checked = Boolean(value);
  } else {
    input.value = value === undefined || value === null ? '' : value;
  }
}

function getConfigInput(name) {
  const input = root.querySelector('[data-cfg="' + name + '"]');
  if (!input) return '';

  if (input.type === 'checkbox') return input.checked;
  return input.value;
}

function openConfig() {
  setConfigInput('entity', getEntityId());
  setConfigInput('icon', getIcon());
  setConfigInput('label', getLabel());
  setConfigInput('style', getSwitchStyle());
  setConfigInput('showBrightness', getShowBrightness());
  setConfigInput('defaultBrightness', getDefaultBrightness());
  setConfigInput('colorOn', card.dataset.colorOn || '#ffd95a');
  setConfigInput('colorAlt', card.dataset.colorAlt || '#4aa7ff');
  setConfigInput('colorOff', card.dataset.colorOff || '#6f7f96');

  configPanel.classList.add('open');
}

function closeConfig() {
  configPanel.classList.remove('open');
}

async function saveConfig() {
  applyConfigObject({
    entity: getConfigInput('entity'),
    icon: getConfigInput('icon'),
    label: getConfigInput('label'),
    style: getConfigInput('style'),
    showBrightness: getConfigInput('showBrightness') ? 'true' : 'false',
    defaultBrightness: getConfigInput('defaultBrightness'),
    colorOn: getConfigInput('colorOn'),
    colorAlt: getConfigInput('colorAlt'),
    colorOff: getConfigInput('colorOff')
  });

  const persistPromise = persistCurrentConfig();
  optimisticState = null;
  lastSignature = '';
  lastStateSignature = '';
  lastScaleSignature = '';

  render(true);
  closeConfig();

  try { await persistPromise; } catch {}
}

function percentFromDimmerEvent(ev, el, mode) {
  const rect = el.getBoundingClientRect();

  if (mode === 'vertical') {
    const y = clamp(ev.clientY - rect.top, 0, rect.height);
    return clamp(Math.round((1 - y / rect.height) * 100), 1, 100);
  }

  const cx = rect.left + rect.width / 2;
  const cy = rect.top + rect.height / 2;
  const dx = ev.clientX - cx;
  const dy = ev.clientY - cy;
  const deg = (Math.atan2(dy, dx) * 180 / Math.PI + 450) % 360;
  return clamp(Math.round((deg / 360) * 100), 1, 100);
}

function previewDimmer(ev) {
  if (!activeDimmer) return;
  const percent = percentFromDimmerEvent(ev, activeDimmer.el, activeDimmer.mode);
  setOptimistic(true, percent);
}

function commitDimmer(ev) {
  if (!activeDimmer) return;
  const percent = percentFromDimmerEvent(ev, activeDimmer.el, activeDimmer.mode);
  const target = activeDimmer.el;
  activeDimmer = null;
  try { target.releasePointerCapture(ev.pointerId); } catch {}
  setBrightness(percent);
}

function onDimmerPointerDown(ev) {
  const target = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-dimmer]') : null;
  if (!target) return;
  ev.preventDefault();
  ev.stopPropagation();

  activeDimmer = {
    el: target,
    mode: target.dataset.nlcDimmer || 'vertical'
  };

  try { target.setPointerCapture(ev.pointerId); } catch {}
  previewDimmer(ev);
}

function onDimmerPointerMove(ev) {
  if (!activeDimmer) return;
  ev.preventDefault();
  ev.stopPropagation();
  previewDimmer(ev);
}

function onDimmerPointerUp(ev) {
  if (!activeDimmer) return;
  ev.preventDefault();
  ev.stopPropagation();
  commitDimmer(ev);
}

function onToggleClick(ev) {
  const commandTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-command]') : null;
  const dimmerTarget = ev.target && ev.target.closest ? ev.target.closest('[data-nlc-dimmer]') : null;
  if (dimmerTarget) return;

  if (commandTarget) {
    ev.preventDefault();
    ev.stopPropagation();
    const command = commandTarget.dataset.nlcCommand;
    if (command === 'on') return setLightState(true, getLightData().percent || getDefaultBrightness());
    if (command === 'off') return setLightState(false, 0);
  }

  ev.preventDefault();
  ev.stopPropagation();
  toggleLight();
}

function onToggleKey(ev) {
  if (ev.key !== 'Enter' && ev.key !== ' ') return;
  ev.preventDefault();
  toggleLight();
}

const onConfigOpen = (ev) => {
  ev.stopPropagation();
  openConfig();
};

const onConfigClose = (ev) => {
  ev.stopPropagation();
  closeConfig();
};

const onConfigSave = (ev) => {
  ev.stopPropagation();
  saveConfig();
};

const onConfigBackdrop = (ev) => {
  if (ev.target === configPanel) closeConfig();
};

toggleTarget.addEventListener('click', onToggleClick);
toggleTarget.addEventListener('keydown', onToggleKey);
toggleTarget.addEventListener('pointerdown', onDimmerPointerDown);
toggleTarget.addEventListener('pointermove', onDimmerPointerMove);
toggleTarget.addEventListener('pointerup', onDimmerPointerUp);
toggleTarget.addEventListener('pointercancel', onDimmerPointerUp);
configOpen.addEventListener('click', onConfigOpen);
configClose.addEventListener('click', onConfigClose);
configSave.addEventListener('click', onConfigSave);
configPanel.addEventListener('click', onConfigBackdrop);

function makeHassStateSignature() {
  const entityId = getEntityId();
  const stateObj = liveHass && liveHass.states ? liveHass.states[entityId] : null;
  return [
    entityId,
    stateObj && stateObj.state || '',
    stateObj && stateObj.last_changed || '',
    stateObj && stateObj.last_updated || '',
    stateObj && stateObj.attributes && stateObj.attributes.brightness || ''
  ].join('|');
}

function render(force) {
  if (destroyed) return;

  syncDesignSurface();

  const data = getLightData();
  const style = getSwitchStyle();
  const entityId = getEntityId();
  const icon = getIcon();
  const label = getLabel();
  const showBrightness = getShowBrightness();
  const colorOn = card.dataset.colorOn || '#ffd95a';
  const colorAlt = card.dataset.colorAlt || '#4aa7ff';
  const colorOff = card.dataset.colorOff || '#6f7f96';

  const signature = [
    entityId,
    icon,
    label,
    style,
    data.state,
    data.on,
    data.percent,
    data.unavailable,
    showBrightness,
    colorOn,
    colorAlt,
    colorOff,
    lastSurfaceSignature
  ].join('|');

  if (!force && signature === lastSignature) {
    updateScale();
    return;
  }

  lastSignature = signature;

  card.dataset.style = style;
  card.dataset.active = data.on ? 'on' : 'off';
  card.dataset.unavailable = data.unavailable ? 'true' : 'false';
  card.dataset.showBrightness = showBrightness ? 'true' : 'false';
  card.style.setProperty('--nlc-on', colorOn);
  card.style.setProperty('--nlc-alt', colorAlt);
  card.style.setProperty('--nlc-off', colorOff);
  card.style.setProperty('--nlc-brightness', data.percent + '%');

  toggleTarget.setAttribute('aria-label', (data.on ? 'Turn off ' : 'Turn on ') + label);
  toggleTarget.setAttribute('aria-pressed', data.on ? 'true' : 'false');
  iconEl.setAttribute('icon', icon);
  labelEl.textContent = label;
  cardNameEl.textContent = label;
  statusEl.textContent = data.unavailable ? 'Unavailable' : (data.on ? 'ON' : 'OFF');
  percentEl.textContent = data.percent + '%';

  const cardPill = root.querySelector('.nlc-card-pill');
  if (cardPill) cardPill.textContent = data.on ? 'ON' : 'OFF';

  updateScale();
}

applyPersistedConfig();
syncDesignSurface();
render(true);
updateScale();

return {
  update(ctx) {
    liveHass = (ctx && ctx.hass) || (host && host.hass) || liveHass;
    const stateSignature = makeHassStateSignature();
    if (stateSignature === lastStateSignature) {
      updateScale();
      return;
    }
    lastStateSignature = stateSignature;
    render(false);
  },
  destroy() {
    destroyed = true;
    try { resizeObserver.disconnect(); } catch {}
    try { surfaceMutationObserver && surfaceMutationObserver.disconnect && surfaceMutationObserver.disconnect(); } catch {}
    if (resizeFrame) cancelAnimationFrame(resizeFrame);
    if (pulseTimer) clearTimeout(pulseTimer);
    toggleTarget.removeEventListener('click', onToggleClick);
    toggleTarget.removeEventListener('keydown', onToggleKey);
    toggleTarget.removeEventListener('pointerdown', onDimmerPointerDown);
    toggleTarget.removeEventListener('pointermove', onDimmerPointerMove);
    toggleTarget.removeEventListener('pointerup', onDimmerPointerUp);
    toggleTarget.removeEventListener('pointercancel', onDimmerPointerUp);
    configOpen.removeEventListener('click', onConfigOpen);
    configClose.removeEventListener('click', onConfigClose);
    configSave.removeEventListener('click', onConfigSave);
    configPanel.removeEventListener('click', onConfigBackdrop);
  }
};

card.css:
:host {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 0;
}

ha-card,
.shell,
.runtime,
.runtime-content {
  width: 100% !important;
  height: 100% !important;
  min-height: 0 !important;
  box-sizing: border-box !important;
  background: transparent !important;
  box-shadow: none !important;
}

.shell {
  padding: 0 !important;
  gap: 0 !important;
  overflow: hidden !important;
}

.runtime,
.runtime-content {
  overflow: hidden !important;
}

.neo-light-card {
  --nlc-on: #ffd95a;
  --nlc-alt: #4aa7ff;
  --nlc-off: #6f7f96;
  --nlc-current: var(--nlc-off);
  --nlc-brightness: 0%;
  --nlc-default-surface: linear-gradient(145deg, #0a0f1c, #121a2b 58%, #070b13);
  --nlc-surface-background: var(--nlc-design-surface, var(--ddc-card-inner-bg, var(--ddc-card-local-bg, var(--ddc-card-bg, var(--nlc-default-surface)))));
  --nlc-surface-border: var(--ddc-card-border-color, rgba(180,200,255,.14));

  width: 100%;
  height: 100%;
  min-width: 50px;
  min-height: 50px;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  background: transparent;
}

.neo-light-card[data-active="on"] {
  --nlc-current: var(--nlc-on);
}

.nlc-stage {
  width: 360px;
  height: 500px;
  position: absolute;
  top: 0;
  left: 0;
  transform-origin: top left;
  will-change: transform;
}

.nlc-switch {
  width: 360px;
  height: 500px;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  border-radius: 42px;
  border: 1px solid var(--nlc-surface-border);
  color: #f7fbff;
  background:
    radial-gradient(circle at 50% 38%, color-mix(in srgb, var(--nlc-current) 12%, transparent), transparent 35%),
    radial-gradient(circle at 50% 52%, rgba(255,255,255,.045), transparent 54%),
    var(--nlc-surface-background);
  box-shadow:
    0 18px 44px rgba(0,0,0,.36),
    inset 0 1px 0 rgba(255,255,255,.065);
  cursor: pointer;
  outline: none;
  user-select: none;
  touch-action: manipulation;
}

.nlc-switch::before,
.nlc-switch::after {
  content: "";
  position: absolute;
  inset: 1px;
  border-radius: inherit;
  pointer-events: none;
}

.nlc-switch::before {
  background:
    linear-gradient(180deg, rgba(255,255,255,.09), transparent 38%),
    radial-gradient(circle at 50% 102%, color-mix(in srgb, var(--nlc-current) 16%, transparent), transparent 34%);
}

.nlc-switch::after {
  inset: 0;
  background:
    linear-gradient(90deg, transparent, rgba(255,255,255,.033), transparent),
    radial-gradient(circle at 48% 42%, color-mix(in srgb, var(--nlc-current) 10%, transparent), transparent 33%);
}

.nlc-switch:focus-visible {
  border-color: color-mix(in srgb, var(--nlc-current) 70%, rgba(255,255,255,.25));
  box-shadow:
    0 18px 44px rgba(0,0,0,.36),
    0 0 0 3px color-mix(in srgb, var(--nlc-current) 32%, transparent),
    inset 0 1px 0 rgba(255,255,255,.065);
}

.neo-light-card[data-surface="transparent"] .nlc-switch {
  background: transparent;
  border-color: transparent;
  box-shadow: none;
}

.neo-light-card[data-surface="transparent"] .nlc-switch::before,
.neo-light-card[data-surface="transparent"] .nlc-switch::after {
  display: none;
}

.nlc-ambient {
  position: absolute;
  left: 50%;
  top: 45%;
  width: 210px;
  height: 210px;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  background: radial-gradient(circle, color-mix(in srgb, var(--nlc-current) 23%, transparent), transparent 66%);
  opacity: .78;
  z-index: 0;
  transition: opacity .3s ease, transform .35s ease;
}

.neo-light-card[data-active="off"] .nlc-ambient {
  opacity: .16;
  transform: translate(-50%, -50%) scale(.82);
}

.nlc-element {
  display: none;
  position: absolute;
  z-index: 2;
}

.nlc-meta {
  position: absolute;
  left: 26px;
  right: 26px;
  bottom: 42px;
  z-index: 4;
  display: grid;
  justify-items: center;
  gap: 10px;
  text-align: center;
  pointer-events: none;
}

.nlc-meta-icon {
  color: var(--nlc-current);
  --mdc-icon-size: 42px;
  filter: drop-shadow(0 0 15px color-mix(in srgb, var(--nlc-current) 34%, transparent));
  transition: color .25s ease, opacity .25s ease;
}

.neo-light-card[data-active="off"] .nlc-meta-icon {
  opacity: .68;
  filter: none;
}

.nlc-label {
  max-width: 100%;
  color: rgba(232,240,255,.72);
  font-size: 24px;
  font-weight: 700;
  line-height: 1.12;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.nlc-status-row {
