    linear-gradient(90deg, color-mix(in srgb, var(--nlc-alt) 62%, rgba(5,10,18,.8)), color-mix(in srgb, var(--nlc-current) 48%, rgba(5,10,18,.74))),
    linear-gradient(145deg, rgba(5,10,18,.78), rgba(45,57,78,.52));
  box-shadow:
