}

.nlc-config-backdrop.open {
  display: grid;
  pointer-events: auto;
}

.nlc-config-panel {
  position: relative;
  width: 314px;
  max-width: 100%;
  max-height: 100%;
  overflow-y: auto;
  padding: 24px;
  box-sizing: border-box;
  border-radius: 28px;
  border: 1px solid rgba(255,255,255,.13);
